import React from 'react';
import { AbsoluteFill } from 'remotion';
import { z } from 'zod';
import { SlideIn } from '../slide-in/SlideIn';
import { FadeIn } from '../fade-in/FadeIn';
import { Underline } from '../underline/Underline';
import { lowerThirdSchema } from './schema';

export { lowerThirdSchema };
export type LowerThirdProps = z.infer<typeof lowerThirdSchema>;

/**
 * Broadcast-style name + role bar that slides in from the corner with a
 * single accent underline. A restrained scene block composed from `SlideIn`,
 * `FadeIn`, and `Underline` — no chrome, no glow, one earned accent.
 *
 * @example
 * <LowerThird name="Rodrigo" role="CEO, Onda" position="bottom-left" />
 */
export const LowerThird: React.FC<LowerThirdProps> = ({
  name,
  role,
  position,
  delay,
  accent,
  color,
  roleColor,
  accentColor,
  fontSize,
  roleFontSize,
  fontFamily,
}) => {
  const isLeft = position === 'bottom-left';

  // Choreography offsets — frames *after* the name's delay.
  // Role follows the name by 4 frames (the canonical Onda stagger).
  // Underline lands last at +8 frames so the eye reads name -> role -> accent.
  const ROLE_OFFSET = 4;
  const UNDERLINE_OFFSET = 8;

  // SlideIn direction: from 'bottom-left' the name slides in from the left;
  // from 'bottom-right' it slides in from the right. Subtle horizontal travel
  // reinforces which corner the bar belongs to.
  const slideDirection = isLeft ? 'left' : 'right';

  return (
    <AbsoluteFill>
      {/* Position the lower-third 32px from the bottom and 32px from the
          chosen horizontal edge. Padding sits inside the bar so the name and
          role have breathing room without a visible chrome surface. */}
      <div
        style={{
          position: 'absolute',
          bottom: 32,
          left: isLeft ? 32 : undefined,
          right: isLeft ? undefined : 32,
          padding: '16px 24px',
          display: 'flex',
          flexDirection: 'column',
          alignItems: isLeft ? 'flex-start' : 'flex-end',
          gap: 4,
          fontFamily,
        }}
      >
        {/* Name — slides in from the side. Uses the primitive's own spring. */}
        <SlideIn
          text={name}
          delay={delay}
          direction={slideDirection}
          color={color}
          fontSize={fontSize}
          fontFamily={fontFamily}
          distance={16}
          duration={18}
        />

        {/* Role — fades in 4 frames after the name. */}
        <FadeIn
          text={role}
          delay={delay + ROLE_OFFSET}
          color={roleColor}
          fontSize={roleFontSize}
          fontFamily={fontFamily}
          duration={18}
        />

        {/* Accent underline — appears last, only when accent === true.
            The Underline primitive draws its own line; we pass an empty
            string for text so only the accent rule is visible (the name
            above already owns the typography). */}
        {accent ? (
          <div
            style={{
              marginTop: 8,
              alignSelf: isLeft ? 'flex-start' : 'flex-end',
            }}
          >
            <Underline
              text=""
              delay={delay + UNDERLINE_OFFSET}
              color={color}
              accentColor={accentColor}
              fontSize={fontSize}
              fontFamily={fontFamily}
              duration={1}
              lineDelay={0}
              lineThickness={3}
              lineOffset={0}
              lineDuration={10}
            />
          </div>
        ) : null}
      </div>
    </AbsoluteFill>
  );
};

export default LowerThird;

import { z } from 'zod';

/** Zod schema for `LowerThird` props. */
export const lowerThirdSchema = z.object({
  /** The person's name. */
  name: z.string().default('Rodrigo'),
  /** The person's role / title. */
  role: z.string().default('CEO, Onda'),
  /** Which corner of the canvas the bar sits in. */
  position: z.enum(['bottom-left', 'bottom-right']).default('bottom-left'),
  /** Frames before the name slides in. */
  delay: z.number().int().min(0).default(0),
  /** Show the accent underline beneath the name. */
  accent: z.boolean().default(true),
  /** Name color. Defaults to `--onda-text`. */
  color: z.string().default('#F2F2F4'),
  /** Role color. Defaults to `--onda-dim`. */
  roleColor: z.string().default('#8E8E98'),
  /** Underline color. Defaults to `--onda-accent`. */
  accentColor: z.string().default('#D96B82'),
  /** Name font size in px. */
  fontSize: z.number().default(48),
  /** Role font size in px. */
  roleFontSize: z.number().default(22),
  /** Onda display font. */
  fontFamily: z.string().default('"Clash Display", sans-serif'),
});

/** Inferred props for `LowerThird`. */
export type LowerThirdProps = z.infer<typeof lowerThirdSchema>;
